const express = require('express');
const cors = require('cors');
const app = express();

// ❌ INSECURE: Wildcard with credentials
// app.use(cors({ origin: '*', credentials: true }));

// ❌ INSECURE: Dynamic origin reflection without validation
// app.use(cors({ origin: true, credentials: true }));

// ✅ SECURE: Strict origin whitelist
const allowedOrigins = [
  'https://app.example.com',
  'https://admin.example.com',
  'https://mobile.example.com'
];

const corsOptions = {
  origin: (origin, callback) => {
    // Allow requests with no origin (e.g., mobile apps, Postman)
    if (!origin) {
      return callback(null, true);
    }

    if (allowedOrigins.includes(origin)) {
      callback(null, true);
    } else {
      console.warn(`CORS blocked request from unauthorized origin: ${origin}`);
      callback(new Error('Not allowed by CORS policy'));
    }
  },
  credentials: true, // Allow cookies/auth headers
  methods: ['GET', 'POST', 'PUT', 'DELETE'], // Restrict HTTP methods
  allowedHeaders: ['Content-Type', 'Authorization'], // Restrict headers
  exposedHeaders: ['X-Total-Count'], // Expose only necessary headers
  maxAge: 600 // Cache preflight for 10 minutes
};

app.use(cors(corsOptions));

// Protected API endpoint
app.get('/api/user/profile', authenticateUser, (req, res) => {
  res.json({
    userId: req.user.id,
    email: req.user.email,
    profile: req.user.profile
  });
});

// Middleware to verify JWT token
function authenticateUser(req, res, next) {
  const token = req.cookies.authToken || req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });

  // Verify token and attach user to request
  try {
    req.user = verifyJWT(token);
    next();
  } catch (err) {
    res.status(403).json({ error: 'Invalid token' });
  }
}

app.listen(3000, () => console.log('Server running with secure CORS'));

package com.example.api.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.CorsConfigurationSource;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;
import org.springframework.web.filter.CorsFilter;
import java.util.Arrays;

@Configuration
public class SecurityConfig {

    // ❌ INSECURE: Never do this
    // @CrossOrigin(origins = "*", allowCredentials = "true")

    // ✅ SECURE: Global CORS configuration with strict origins
    @Bean
    public CorsFilter corsFilter() {
        CorsConfiguration config = new CorsConfiguration();

        // Strict origin whitelist
        config.setAllowedOrigins(Arrays.asList(
            "https://app.example.com",
            "https://admin.example.com",
            "https://mobile.example.com"
        ));

        // Allow credentials (cookies, auth headers)
        config.setAllowCredentials(true);

        // Restrict HTTP methods
        config.setAllowedMethods(Arrays.asList("GET", "POST", "PUT", "DELETE", "OPTIONS"));

        // Restrict headers
        config.setAllowedHeaders(Arrays.asList(
            "Authorization",
            "Content-Type",
            "X-Requested-With"
        ));

        // Expose only necessary headers
        config.setExposedHeaders(Arrays.asList("X-Total-Count", "X-Page-Number"));

        // Cache preflight requests for 1 hour
        config.setMaxAge(3600L);

        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
        source.registerCorsConfiguration("/**", config);

        return new CorsFilter(source);
    }
}

