// config/cors.config.js
require('dotenv').config();

class CorsConfig {
  constructor() {
    this.allowedOrigins = this.parseAllowedOrigins();
    this.validateConfiguration();
  }

  parseAllowedOrigins() {
    const originsEnv = process.env.CORS_ALLOWED_ORIGINS;

    if (!originsEnv) {
      throw new Error('CORS_ALLOWED_ORIGINS environment variable is required');
    }

    return originsEnv.split(',').map(origin => origin.trim());
  }

  validateConfiguration() {
    // Ensure no wildcard with credentials
    if (this.allowedOrigins.includes('*') && process.env.CORS_ALLOW_CREDENTIALS === 'true') {
      throw new Error('SECURITY ERROR: Cannot use wildcard origin (*) with credentials enabled');
    }

    // Validate all origins use HTTPS in production
    if (process.env.NODE_ENV === 'production') {
      this.allowedOrigins.forEach(origin => {
        if (origin !== 'null' && !origin.startsWith('https://')) {
          throw new Error(`SECURITY ERROR: Production origin must use HTTPS: ${origin}`);
        }
      });
    }

    console.log('✅ CORS configuration validated successfully');
    console.log('Allowed origins:', this.allowedOrigins);
  }

  isOriginAllowed(origin) {
    if (!origin) {
      return process.env.CORS_ALLOW_NO_ORIGIN === 'true';
    }

    // Exact match
    if (this.allowedOrigins.includes(origin)) {
      return true;
    }

    // Pattern-based matching for subdomains (e.g., *.example.com)
    return this.allowedOrigins.some(pattern => {
      if (pattern.startsWith('*.')) {
        const domain = pattern.substring(2);
        const regex = new RegExp(`^https://[a-z0-9-]+\\.${domain.replace('.', '\\.')}$`, 'i');
        return regex.test(origin);
      }
      return false;
    });
  }

  getCorsOptions() {
    return {
      origin: (origin, callback) => {
        if (this.isOriginAllowed(origin)) {
          callback(null, true);
        } else {
          console.warn(`🚫 CORS blocked: ${origin || 'no-origin'}`);
          // Log to SIEM for security monitoring
          this.logSecurityEvent('cors_blocked', { origin, timestamp: new Date() });
          callback(new Error('Not allowed by CORS'));
        }
      },
      credentials: process.env.CORS_ALLOW_CREDENTIALS === 'true',
      methods: (process.env.CORS_ALLOWED_METHODS || 'GET,POST,PUT,DELETE').split(','),
      allowedHeaders: (process.env.CORS_ALLOWED_HEADERS || 'Content-Type,Authorization').split(','),
      exposedHeaders: (process.env.CORS_EXPOSED_HEADERS || '').split(',').filter(Boolean),
      maxAge: parseInt(process.env.CORS_MAX_AGE || '600', 10)
    };
  }

  logSecurityEvent(eventType, details) {
    // Send to SIEM or logging service
    console.log(JSON.stringify({
      event_type: eventType,
      severity: 'warning',
      ...details
    }));
  }
}

module.exports = new CorsConfig();

